#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

inline int maximum_int(int a, int b, int c) {
    int k = (a <= b) ? b : a;
    return (k <= c) ? c : k;
}

__kernel void nw_kernel1(__global int* reference,
                         __global int* input_itemsets,
                         __global int* output_itemsets,
                         __local int* input_itemsets_l,
                         __local int* reference_l,
                         int max_cols,
                         int penalty,
                         int blk,
                         int block_width,
                         int worksize,
                         int offset_r,
                         int offset_c)
{
    (void)output_itemsets;
    (void)block_width;
    (void)worksize;

    const int tx = get_local_id(0);
    const int bx = get_group_id(0);

    if (tx == 0) {
        const int b_index_x = bx;
        const int b_index_y = blk - 1 - bx;

        for (int i = 0; i < BLOCK_SIZE; ++i) {
            for (int j = 0; j < BLOCK_SIZE; ++j) {
                reference_l[i * BLOCK_SIZE + j] =
                    reference[max_cols * (b_index_y * BLOCK_SIZE + i + 1 + offset_r) +
                              (b_index_x * BLOCK_SIZE + j + 1 + offset_c)];
            }
        }

        for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
            for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                    input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + offset_r) +
                                   (b_index_x * BLOCK_SIZE + j + offset_c)];
            }
        }

        for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
            for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum_int(
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + (j - 1)] +
                        reference_l[(i - 1) * BLOCK_SIZE + (j - 1)],
                    input_itemsets_l[i * (BLOCK_SIZE + 1) + (j - 1)] - penalty,
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty
                );
            }
        }

        for (int i = 0; i < BLOCK_SIZE; ++i) {
            for (int j = 0; j < BLOCK_SIZE; ++j) {
                input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1 + offset_r) +
                               (b_index_x * BLOCK_SIZE + j + 1 + offset_c)] =
                    input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + (j + 1)];
            }
        }
    }
}

